#!/usr/bin/env node
// Stagecraft bundle script — concatenates runtime JS and theme CSS into dist/.
// No external deps. Plain output (no minify, no source maps).

import { readFileSync, writeFileSync, mkdirSync, readdirSync, existsSync } from 'node:fs';
import { dirname, join, relative, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, '..');
const SRC = join(ROOT, 'src');
const THEMES = join(ROOT, 'themes');
const DIST = join(ROOT, 'dist');
const DIST_THEMES = join(DIST, 'themes');

function ensureDir(p) {
  mkdirSync(p, { recursive: true });
}

function readRel(absPath) {
  return readFileSync(absPath, 'utf8');
}

function banner(relPath) {
  return `// === ${relPath} ===\n`;
}

// --- JS bundle -------------------------------------------------------------

function buildJsBundle() {
  const order = [];

  order.push(join(SRC, 'helpers.js'));
  order.push(join(SRC, 'engine.js'));
  order.push(join(SRC, 'transitions.js'));

  const componentsDir = join(SRC, 'components');
  const components = readdirSync(componentsDir)
    .filter((f) => f.endsWith('.js'))
    .sort();
  for (const f of components) {
    order.push(join(componentsDir, f));
  }

  order.push(join(SRC, 'edit-mode.js'));

  const parts = [];
  parts.push('// Stagecraft bundle — generated by scripts/bundle.js. Do not edit by hand.\n');
  for (const abs of order) {
    const rel = relative(ROOT, abs).split(/[\\/]/).join('/');
    parts.push(banner(rel));
    parts.push(readRel(abs));
    if (!parts[parts.length - 1].endsWith('\n')) parts.push('\n');
    parts.push('\n');
  }

  const out = parts.join('');
  const outPath = join(DIST, 'stagecraft.bundle.js');
  ensureDir(DIST);
  writeFileSync(outPath, out, 'utf8');
  return { outPath, bytes: Buffer.byteLength(out, 'utf8'), fileCount: order.length };
}

// --- CSS bundle ------------------------------------------------------------

// Resolve @import url('./relative.css') by inlining the referenced file's contents.
// Naive: only handles `@import url('...')` and `@import url("...")` and `@import '...';`.
function inlineCssImports(cssText, fromDir, visited = new Set()) {
  const importRe = /@import\s+(?:url\(\s*['"]?([^'")]+)['"]?\s*\)|['"]([^'"]+)['"])\s*;?/g;
  return cssText.replace(importRe, (match, urlPath, barePath) => {
    const importPath = urlPath || barePath;
    if (!importPath) return match;
    // Leave absolute URLs (http(s), //) alone.
    if (/^(https?:)?\/\//i.test(importPath)) return match;

    const resolved = resolve(fromDir, importPath);
    if (visited.has(resolved)) return `/* circular @import skipped: ${importPath} */`;
    if (!existsSync(resolved)) return `/* missing @import: ${importPath} */`;

    visited.add(resolved);
    const childCss = readFileSync(resolved, 'utf8');
    const inlined = inlineCssImports(childCss, dirname(resolved), visited);
    const rel = relative(ROOT, resolved).split(/[\\/]/).join('/');
    return `/* === inlined: ${rel} === */\n${inlined}`;
  });
}

function buildThemeCssBundle(themeName) {
  const themeDir = join(THEMES, themeName);
  const files = ['tokens.css', 'base.css', 'components.css', 'transitions.css'];
  const parts = [];
  parts.push(`/* Stagecraft theme bundle: ${themeName} — generated by scripts/bundle.js. */\n`);

  let count = 0;
  for (const f of files) {
    const abs = join(themeDir, f);
    if (!existsSync(abs)) continue;
    count++;
    const rel = relative(ROOT, abs).split(/[\\/]/).join('/');
    parts.push(`/* === ${rel} === */\n`);
    const css = readFileSync(abs, 'utf8');
    parts.push(inlineCssImports(css, themeDir, new Set([abs])));
    if (!parts[parts.length - 1].endsWith('\n')) parts.push('\n');
    parts.push('\n');
  }

  const out = parts.join('');
  ensureDir(DIST_THEMES);
  const outPath = join(DIST_THEMES, `${themeName}.bundle.css`);
  writeFileSync(outPath, out, 'utf8');
  return { outPath, bytes: Buffer.byteLength(out, 'utf8'), fileCount: count };
}

// --- Run -------------------------------------------------------------------

function fmtBytes(n) {
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
  return `${(n / 1024 / 1024).toFixed(2)} MB`;
}

console.log('Stagecraft bundle');
console.log('-----------------');

const js = buildJsBundle();
console.log(`JS:  ${relative(ROOT, js.outPath)}  (${js.fileCount} files, ${fmtBytes(js.bytes)})`);

const themes = ['phosphor', 'paper', 'neon', 'brand', 'shopware'];
let cssTotal = 0;
let cssFileCount = 0;
const cssBundles = [];
for (const t of themes) {
  const dir = join(THEMES, t);
  if (!existsSync(dir)) {
    console.log(`CSS: ${t} — skipped (no themes/${t})`);
    continue;
  }
  const r = buildThemeCssBundle(t);
  cssTotal += r.bytes;
  cssFileCount += r.fileCount;
  cssBundles.push(r);
  console.log(`CSS: ${relative(ROOT, r.outPath)}  (${r.fileCount} files, ${fmtBytes(r.bytes)})`);
}

// Also write a top-level dist/stagecraft.bundle.css that is the default (phosphor),
// for convenience as described in the spec.
const defaultCssSource = join(DIST_THEMES, 'phosphor.bundle.css');
if (existsSync(defaultCssSource)) {
  const defaultOut = join(DIST, 'stagecraft.bundle.css');
  writeFileSync(defaultOut, readFileSync(defaultCssSource, 'utf8'), 'utf8');
  const bytes = Buffer.byteLength(readFileSync(defaultOut, 'utf8'), 'utf8');
  console.log(`CSS: ${relative(ROOT, defaultOut)}  (alias of phosphor, ${fmtBytes(bytes)})`);
}

const total = js.bytes + cssTotal;
console.log('-----------------');
console.log(`Total: ${js.fileCount + cssFileCount} source files, ${fmtBytes(total)} written.`);
